import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const AdminDashboard = () => {
  const [plans, setPlans] = useState([]);
  const [form, setForm] = useState({
    name: "",
    price: "",
    duration: "monthly",
    features: "",
  });

  const fetchPlans = async () => {
    try {
      const res = await axiosInstance.get("/api/plans");
      setPlans(res.data);
    } catch (error) {
      console.error("ADMIN FETCH PLANS ERROR:", error);
      alert("Failed to load plans");
    }
  };

  const handleCreate = async () => {
    if (!form.name || !form.price) {
      return alert("Name and price are required");
    }

    try {
      await axiosInstance.post("/api/plans", {
        name: form.name,
        price: Number(form.price),
        duration: form.duration,
        features: form.features
          ? form.features.split(",").map((f) => f.trim())
          : [],
      });

      setForm({
        name: "",
        price: "",
        duration: "monthly",
        features: "",
      });

      fetchPlans();
    } catch (error) {
      console.error(
        "ADMIN CREATE PLAN ERROR:",
        error.response?.data || error.message
      );
      alert("Failed to create plan");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/plans/${id}`);
      fetchPlans();
    } catch (error) {
      console.error(
        "ADMIN DELETE PLAN ERROR:",
        error.response?.data || error.message
      );
      alert("Failed to delete plan");
    }
  };

  useEffect(() => {
    fetchPlans();
  }, []);

  return (
    <div className="container">
      {/* PAGE HEADER */}
      <div className="mb-4">
        <h1 className="page-title">Admin Dashboard</h1>
        <p style={{ textAlign: "center", color: "#666" }}>
          Manage subscription plans and pricing
        </p>
      </div>

      {/* CREATE PLAN CARD */}
      <div className="card">
        <h2 className="mb-4">Create New Plan</h2>

        <div className="mb-2">
          <input
            type="text"
            placeholder="Plan name"
            value={form.name}
            onChange={(e) =>
              setForm({ ...form, name: e.target.value })
            }
          />
        </div>

        <div className="mb-2">
          <input
            type="number"
            placeholder="Price (AUD)"
            value={form.price}
            onChange={(e) =>
              setForm({ ...form, price: e.target.value })
            }
          />
        </div>

        <div className="mb-2">
          <select
            value={form.duration}
            onChange={(e) =>
              setForm({ ...form, duration: e.target.value })
            }
          >
            <option value="monthly">Monthly</option>
            <option value="yearly">Yearly</option>
          </select>
        </div>

        <div className="mb-4">
          <input
            type="text"
            placeholder="Features (comma separated)"
            value={form.features}
            onChange={(e) =>
              setForm({ ...form, features: e.target.value })
            }
          />
        </div>

        <button
          onClick={handleCreate}
          className="btn-primary"
          style={{ width: "100%" }}
        >
          Create Plan
        </button>
      </div>

      {/* PLAN LIST */}
      <div className="mt-4">
        <h2 className="mb-4">Existing Plans</h2>

        {plans.length === 0 && (
          <p style={{ color: "#777" }}>No plans available</p>
        )}

        {plans.map((plan) => (
          <div key={plan._id} className="card">
            <div className="flex">
              <div>
                <h3>{plan.name}</h3>
                <p style={{ color: "#555" }}>
                  ${plan.price} • {plan.duration}
                </p>
              </div>

              <button
                onClick={() => handleDelete(plan._id)}
                className="btn-danger"
              >
                Delete
              </button>
            </div>

            {/* FEATURES */}
            {plan.features?.length > 0 && (
              <ul style={{ marginTop: "10px", paddingLeft: "20px" }}>
                {plan.features.map((feature, index) => (
                  <li key={index} style={{ color: "#666" }}>
                    {feature}
                  </li>
                ))}
              </ul>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminDashboard;
